// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check data general', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check data general', async function() {
    // Test name: Check data general
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/list-evaluation | 
    await driver.get("http://localhost:4200/user/list-evaluation");

    // 2 | setWindowSize | 1936x1056 | 
    await driver.manage().window().setRect({ width: 1936, height: 1056 });

    // 3 | click | css=.ant-layout-content | 
    await driver.findElement(By.css(".ant-layout-content")).click();

    // 4 | click | css=.ant-btn-primary > span | 
    await driver.findElement(By.css(".ant-btn-primary > span")).click();

    // 5 | click | css=.ant-table-cell-row-hover:nth-child(1) | 
    await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(1)")).click();

    // 6 | verifyText | css=.ant-form-item:nth-child(2) .ant-form-item-control-input-content | 2022/4 ~ 2022/09
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(2) .ant-form-item-control-input-content")).getText() == "2022/4 ~ 2022/09");

    // 7 | verifyText | css=.ant-form-item:nth-child(3) .ant-form-item-control-input-content | 2011111 : Nguyen HoangThien
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(3) .ant-form-item-control-input-content")).getText() == "2011111 : Nguyen HoangThien");

    // 8 | verifyText | css=.ant-form-item:nth-child(4) .ant-col-xs-24 .ant-form-item-control-input-content | GNW-1002: GEO SYSTEM VN
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(4) .ant-col-xs-24 .ant-form-item-control-input-content")).getText() == "GNW-1002: GEO SYSTEM VN");

    // 9 | verifyText | css=.ant-form-item:nth-child(5) .ant-form-item-control-input-content | 8
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(5) .ant-form-item-control-input-content")).getText() == "8");

    // 10 | verifyText | css=.ant-form-item:nth-child(6) .ant-form-item-control-input-content | 一次評価：Vo Khanh Duy、二次評価：Vo Thi Huyen Trang
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(6) .ant-form-item-control-input-content")).getText() == "一次評価：Vo Khanh Duy、二次評価：Vo Thi Huyen Trang");

    // 11 | verifyText | css=.ant-form-item:nth-child(7) .ant-form-item-control-input-content | 【目標】作成中
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(7) .ant-form-item-control-input-content")).getText() == "【目標】作成中");
  });
});
